; Auto-generated by breadbox. Do not edit.
; UART 6551: {{ device_id }} ({{ type }})
;
; Driver: W65C51N polling (timed TX delay for TDRE bug workaround)
; Baud rate: {{ baudrate }}
;
; All public procedures use {{ macro_prefix }}::byte (zero page) for parameter passing.
; Public API: init, read, write, write_terminal, load_status.

{% set P = macro_prefix %}

.include "hardware.inc"
.include "core/delay.inc"
.include "{{ build_dir }}/macros.inc"
{% if pin_rts %}
.include "{{ pin_rts.build_dir }}/macros.inc"
{% endif %}

.segment "ZEROPAGE"

    {{ P }}_byte: .res 1                ; Parameter byte for UART operations

.segment "KERNAL"

{% if type == "w65c51" %}
    ; =====================================================================
    ; TX character time (microseconds) for the W65C51N timed-TX workaround.
    ;
    ; The W65C51N has a hardware bug: the TDRE (Transmit Data Register Empty)
    ; status bit is never set. Polling it would spin forever. Instead, we
    ; delay for one full character time (10 bits at baud rate) after each
    ; write to allow the shift register to drain.

    _CHAR_TIME_US = 10000000 / {{ baudrate }}

    .proc _{{ P }}_tx_delay
        DELAY_US _CHAR_TIME_US
        rts
    .endproc

{% endif %}
    ; =====================================================================
    ; Soft reset the ACIA.
    ;
    ; Writing any value to the status register triggers a programmed reset.
    ;
    ; Out:
    ;   A = clobbered

    .proc _{{ P }}_soft_reset
        sta {{ P }}_STATUS
        DELAY_MS 100
        rts
    .endproc

    ; =====================================================================
    ; Initialize the UART.
    ;
    ; Performs a soft reset, configures baud rate and command register,
    ; and asserts the RTS flow control pin (if present).
    ; Called automatically via .constructor.
    ;
    ; Out:
    ;   A = clobbered

    .proc _{{ P }}_init
        jsr _{{ P }}_soft_reset
{% if pin_rts %}

        ; Assert RTS: active low = ready to receive.
        {{ P }}_PIN_RTS_off
{% endif %}

        ; CTRL: 8N1, internal baud rate generator.
        lda #({{ P }}_CTRL_8BIT | {{ P }}_CTRL_1STOP | {{ P }}_CTRL_INTCLK | {{ P }}_CTRL_BAUD)
        sta {{ P }}_CTRL

        ; CMD: no parity, no echo, TX IRQ disabled (/RTS asserted), DTR on.
        ;      RX IRQ disabled for polling mode.
        lda #({{ P }}_CMD_TIC2 | {{ P }}_CMD_DTR | {{ P }}_CMD_IRQOFF)
        sta {{ P }}_CMD

        rts
    .endproc
    .constructor _{{ P }}_init

    ; =====================================================================
    ; Read a byte from the receiver (non-blocking).
    ;
    ; Checks the RDRF status bit. If a byte is waiting, reads it into
    ; the byte variable and returns with carry set. Otherwise returns
    ; with carry clear.
    ;
    ; Out:
    ;   C = 1 if byte received, 0 if buffer empty
    ;   byte = received data (valid only when C=1)
    ;   A = clobbered

    .proc _{{ P }}_read
        clc
        lda {{ P }}_STATUS
        and #{{ P }}_SR_RDRF
        beq @done

        lda {{ P }}_DATA
        sta {{ P }}_byte
        sec
    @done:
        rts
    .endproc

    ; =====================================================================
    ; Write a byte to the transmitter.
    ;
{% if type == "w65c51" %}
    ; After writing, delays for one character time to work around the
    ; W65C51N TDRE bug (the shift register must drain before the next write).
    ;
{% endif %}
    ; In (zero page):
    ;   byte = data byte to transmit
    ; Out:
    ;   A = clobbered

    .proc _{{ P }}_write
        lda {{ P }}_byte
        sta {{ P }}_DATA
{% if type == "w65c51" %}
        jsr _{{ P }}_tx_delay
{% endif %}
        rts
    .endproc

    ; =====================================================================
    ; Write a byte to a terminal.
    ;
    ; Handles CR → CR+LF conversion for terminal-style output.
    ;
    ; In (zero page):
    ;   byte = data byte to transmit
    ; Out:
    ;   A = clobbered

    .proc _{{ P }}_write_terminal
        lda {{ P }}_byte
        cmp #$0d
        bne @raw

        ; Send CR first, then queue LF.
        jsr _{{ P }}_write
        lda #$0a
        sta {{ P }}_byte
    @raw:
        jmp _{{ P }}_write
    .endproc

    ; =====================================================================
    ; Load the ACIA status register into the byte variable.
    ;
    ; Out:
    ;   byte = status register contents
    ;   A = clobbered

    .proc _{{ P }}_load_status
        lda {{ P }}_STATUS
        sta {{ P }}_byte
        rts
    .endproc

; =========================================================================
; Exports
; =========================================================================

{{ exportzp("_byte") }}

{{ export("_init") }}
{{ export("_read") }}
{{ export("_write") }}
{{ export("_write_terminal") }}
{{ export("_load_status") }}
